INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3011_L007$$, 2026, $$Note: FY2025 amounts reflect 9.841M in reductions in the FY25 Appropriation Act.

 The Joint Direct Attack Munition (JDAM) program is a joint Air Force/Navy program with the Air Force as the lead service. Designated ACAT IC, this program upgrades the existing inventory of general purpose
 bombs by integrating the bombs with a field installed guidance kit using a Global Positioning System-aided Inertial Navigation System (GPS/INS). JDAM provides an accurate, adverse weather capability. JDAM
 is integrated with the B-52H, B-2A, B-1B, F-16 (all variants), F/A-18A+/C/D/E/F, F-15E, AV-8B, A-10C, F-22A, F-35, and MQ-9 (500lb. variant) aircraft. Integration with the B-21 is in progress.

 The Air Force is currently procuring Strategic Anti-Jam Beamforming Receiver M-Code (SABR-M) guidance kits which are enhanced GPS-denied environment guidance systems, to meet Section 913 of the
 National Defense Authorization Act for FY 2011 (Public Law 111-383).

 Pursuant to section 2308 of Title 10, U.S. Code, this program will seek cost efficiencies where available through production lot negotiations. This program will continue procurement past FY2030 due to evolving
 warfighter requirements driven by ongoing combat and training expenditures.

 Procurements for the execution year may vary due to changes in inventory objectives. Combatant commanders' requirements for Operational Plans influence these objectives, which are updated throughout the
 year.

 Funds may be used to address production Diminishing Manufacturing Sources (DMS)/Material Shortages/Obsolescence issues through studies, bridge buys, life of type buys, supplier/parts replacement, to
 include electronic components used commercially and in short supply, and qualification activities to preserve future production capabilities and capacities.

 Funding for this exhibit is contained in PE 0207583F.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":7,"src_title":"Joint Direct Attack Munition","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Ammunition Procurement.pdf$$, 53, 53, $$4ae7bf4b3b8c35d1$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3011_L007$$, 2027, $$The Joint Direct Attack Munition (JDAM) program is a joint U.S. Air Force/Navy program led by the Air Force. Designated ACAT 1C, this program improves the existing inventory of general-purpose gravity bombs
 by integrating a Global Positioning System (GPS)/inertial navigation guidance kit that enhances accuracy and adverse weather capability. Laser JDAM (LJDAM) and JDAM Extended Range (JDAM-ER) variants
 increase operational flexibility. JDAM, LJDAM and, JDAM-ER incorporate existing inventory of general-purpose warheads, which can be configured with a variety of fusing systems or proximity sensors. The
 laser sensor kit added for the LJDAM weapon kit can attack targets of opportunity, including moving land and maritime targets, when designated by an airborne or ground laser. The JDAM-ER option is achieved
 through the addition of a modular wing kit. When deployed, these wings unfold, allowing the bomb to glide significantly further than a standard JDAM range. In FY2024 JDAM tail kit procurement transitioned from
 using the Strategic Anti-Jam Beamforming Receiver (SABR) GPS receiver and antenna to M-Code (SABR-M) capable guidance kits to meet Section 913 of the National Defense Authorization Act for FY 2011
 (Public Law 111-383) M-Code GPS requirements which provide enhanced resistance to GPS jamming over earlier production variants. JDAM is currently integrated with B-52H, B-2A, B-1B, F-16 (all variants),
 MQ-9A (500 lbs. variant), F/A-18A+/C/D/E/F, F-15E/EX, AV-8B, A-10C, F-22A, and F-35A aircraft. B-21 is in progress.

 Pursuant to section 2308 of Title 10, U.S. Code, this program will seek cost efficiencies where available through production lot negotiations. This program will continue procurement past FY 2030 due to evolving
 warfighter requirements driven by ongoing combat and training expenditures.

 Procurements for the execution year may vary due to changes in inventory objectives. Combatant commanders' requirements for Operational Plans influence these objectives, which are updated throughout the
 year.

 Funds may be used to address production Diminishing Manufacturing Sources (DMS)/Material Shortages/Obsolescence issues through studies, bridge buys, life of type buys, supplier/parts replacement, to
 include electronic components used commercially and in short supply, and qualification activities to preserve future production capabilities and capacities.

 Funding for this exhibit is contained in PE 0207583F.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Air Force                                                                                                                Date: April 2026
