INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_0300_L107$$, 2026, $$This Line Item funds ordnance items, munitions, small/medium/large caliber ammunition, demolitions, pyrotechnics, explosive initiation devices, underwater munitions, grenades, foreign weapons and
 ammunition, air delivered munitions, precision guided munitions, and rockets for Special Operations Forces (SOF). Ammunition provided will allow SOF components to accomplish the required rapid fielding,
 annual training, support required combat missions and build toward the required war reserve quantities.

 ELEMENT              FY 2025       FY 2026        FY 2027
