INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1507_L040$$, 2026, $$The MK-48 MOD 7 Heavyweight Torpedo is the U.S. Navy's submarine launched Anti-Submarine Warfare (ASW) and primary Anti-Surface Warfare (ASuW) weapon. The Heavyweight Torpedo provides the
 submarine force with an effective weapon against threat submarines and surface combatants to assist in achieving Sea Control and neutralizing or destroying threats to high value vessels. Torpedoes are
 the only proven weapon system that provides Navy control from the sea bed to sea surface. Heavyweight AUR procurement is required to increase Warshot inventory to address increased Naval Munitions
 Requirement Process (NMRP) requirements gap. Additionally new funding added to support Commercial Torpedo, also knows as Rapid Affordable Procurable Torpedo (RAPTOR).

 The FY 2026 spend plan includes $4,581 thousand of discretionary and $381,240 thousand of mandatory (reconciliation) for a total of $385,821 thousand. The discretionary funds cover installations and
 Diminishing Manufacturing Sources. The mandatory funds cover the requirement for the FY2026 MK 48 MOD 7 G&C/WUK (63) for $135,550 thousand, Afterbody/Fuel Tanks Section (63) for $77,094 thousand,
 Engineering Services for $9,394 thousand, 22 Installs for $5,980 thousand, Diminishing Manufacturing Sources for $156 thousand, War Reserve for $14,767 thousand, Production Engineering for $7,708
 thousand, Quality Assurance $2,292 thousand, Acceptance Test & Evaluation $6,303 thousand, Support and Ancillary Equipment $1,996 thousand, and $120,000 thousand for the procurement of commercial
 torpedoes.

