INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L063$$, 2027, $$This line item funds the modifications to the F-5 platform, F-16 platform, and Adversary Mission Systems Modifications. The Adversary aircraft are a combination of 42 F-5 Tiger IIs (39 F-5Ns and 3 F-5Fs), the
 J85 Engine supporting the F-5, 14 Block 15 F-16 Fighting Falcon (10 F-16As and 4 F-16Bs), 31 Block 25/32 F-16 Fighting Falcon (24 F-16Cs and 7 F-16Ds), and the F-100 Engine supporting the F-16. The
 Adversary aircraft provide essential sorties in support of TOPGUN, Fleet Replacement Squadron, Carrier Strike Group, Carrier Air Wing and Unit Deployment Plan. Both the F-5s and the F-16s are planned to be
 used as primary Adversary mission through the 2030+. An additional 31 F-16s (24 Block 32 F-16Cs and 7 Block 25 F-16Ds) began transferring in April 2022 from the United States Air Force/Air National Guard,
 with the final aircraft scheduled for transfer in summer 2026. These aircraft will be upgraded to maintain common configuration with the USAF program. Adversary Missions Systems will provide peer threat
 replication and support future integration of Live, Virtual, and Constructive (LVC) capabilities.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                              Date: April 2026
