INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L041$$, 2027, $$This line item funds major and minor modifications needed to mitigate safety issues and correct deficiencies on aging Navy T-6 Primary trainer and AT6E Light Attack aircraft systems. These modifications are
 fielded through Engineering Change Proposals (ECP) to mitigate emergent issues related to safety, obsolescence, diminishing manufacturing sources, material shortages, reliability, maintainability and gaps in
 system capabilities identified in the Program Objective Memorandum (POM).

 The Navy T-6 aircraft and Ground Based Training Systems (GBTS) are managed by Program Management Air (PMA) 273 who resources Integrated Product Teams within the U.S. Air Force led Joint Primary
 Aircraft Training System (JPATS) program office. A primary role of JPATS is the execution of modification programs needed to maintain trainer aircraft readiness and meet system support needs of the Chief
 of Naval Air Training (CNATRA) whose mission is to train Student Naval Aviators (SNA) and Naval Flight Officers (NFO). The T-6 aircraft is a commercially developed and certified tandem ejection seat trainer
 aircraft powered by a single Pratt and Whitney turboprop engine.

 The Navy T-6 inventory is 295 aircraft (43 T-6A's, 250 T-6B's and 2 AT-6E's). The T-6A conducts NFO training at NAS Pensacola, FL while the T-6B conducts SNA training at NAS Whiting Field, FL and NAS
 Corpus Christi, TX. The Naval Test Pilot School in Patuxent River, MD utilizes six T-6B's and 2 AT-6E's to fulfill test and evaluation curriculum criteria. The Navy supports and operates 34 Ground Based Training
 System (GBTS) units (7 T-6A and 27 T-6B) to conduct T-6 simulated training to SNA's and NFO's. The Department of the Navy received delivery of final production training Aircraft in 2016 and the AT-6E through
 transfer from the USAF in 2023.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
