INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L042$$, 2026, $$Provides funding for procurement of aircraft modification kits and installation to support integration of Improved Joint Helmet Mounted Cueing System (IJHMCS), the upgraded helmet mounted solution for the F/
 A-18 E/F and EA-18G aircraft.

 IJHMCS has been resourced to address legacy JHMCS obsolescence, reduce weight, and improve center of gravity to mitigate chronic back and neck injury, and reduce injury risk during ejection. System
 technology refresh enables head up display (HUD) of aircraft and tactical situational awareness enhancements programmed for the cockpit displays. IJHMCS replaces legacy JHMCS and Night Vision Cueing
 Device (NVCD) with a single day/night high-definition color capable display of critical flight parameters and tactical data.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
