INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1506_L045$$, 2026, $$The Common Defensive Weapon System (CDWS) consists of GAU-21 .50 caliber Machine Gun, GAU-17, GAU-24, and M240D, cradles, ammo boxes, feed/link chutes, lasers, and platform specific mount
 systems for US Navy and Marine Corps assault and assault support helicopter platforms to include the MV-22, CH-53E/K, UH-1Y, and MH-60 R/S. This budget procures and replaces the one for one weapon as
 it is determined to be Beyond Capable Maintenance (BCM), to the fleet forces. CDWS modifications enhance the warfighters overall capability by providing a safer, more reliable and accurate weapon system
 with a higher rate of fire. For the CH-53K, which is in production, procurement of the Ramp, Door and Window mounted CDWS may be procured. Funding also supports modification and improvements of Crew
 Served Weapons Systems, the GAU-21, GAU-17, GAU-24, GPU-8/9A (GAU-22), and M240D.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
